from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a building into a single fluent sentence.
    """
    if not triples:
        return ""

    # Identify the main building subject (most common subject)
    subject_counts = {}
    for t in triples:
        subject_counts[t.subject] = subject_counts.get(t.subject, 0) + 1
    main_subject = max(subject_counts, key=subject_counts.get) if subject_counts else None

    if not main_subject:
        return ""

    # Build a map of all predicates for the main subject
    main_info = {}
    related_subjects = {}

    for t in triples:
        if t.subject == main_subject:
            main_info[t.predicate] = t.object
        else:
            # Track related subjects (for location hierarchies)
            if t.predicate in ['country', 'isPartOf', 'state', 'region']:
                related_subjects[t.predicate] = t.object

    # Build sentence parts efficiently
    sentence_parts = []

    # Start with building name and type
    building_type = main_info.get('buildingType', '')
    if building_type:
        sentence_parts.append(f"{main_subject}, a {building_type}")
    else:
        sentence_parts.append(main_subject)

    # Add architect information
    if 'architect' in main_info:
        sentence_parts.append(f"designed by {main_info['architect']}")

    # Add architectural style
    if 'architecturalStyle' in main_info:
        sentence_parts.append(f"with {main_info['architecturalStyle']} architecture")

    # Add location information (chain hierarchies)
    if 'location' in main_info:
        sentence_parts.append(f"located at {main_info['location']}")
    elif related_subjects:
        loc_parts = []
        if 'country' in related_subjects:
            loc_parts.append(related_subjects['country'])
        if 'state' in related_subjects:
            loc_parts.append(related_subjects['state'])
        if 'region' in related_subjects:
            loc_parts.append(related_subjects['region'])
        if 'isPartOf' in related_subjects:
            loc_parts.append(related_subjects['isPartOf'])
        if loc_parts:
            sentence_parts.append(f"in {', '.join(loc_parts)}")

    # Add physical attributes
    if 'height' in main_info:
        sentence_parts.append(f"standing {main_info['height']} tall")

    if 'floorCount' in main_info:
        sentence_parts.append(f"with {main_info['floorCount']} floors")

    if 'numberOfRooms' in main_info:
        sentence_parts.append(f"containing {main_info['numberOfRooms']} rooms")

    # Add dates
    if 'completionDate' in main_info:
        sentence_parts.append(f"completed in {main_info['completionDate']}")
    elif 'yearOfConstruction' in main_info:
        sentence_parts.append(f"built in {main_info['yearOfConstruction']}")

    # Add owner/developer info
    if 'owner' in main_info:
        sentence_parts.append(f"owned by {main_info['owner']}")
    elif 'developer' in main_info:
        sentence_parts.append(f"developed by {main_info['developer']}")

    # Add cost information
    if 'cost' in main_info:
        sentence_parts.append(f"at a cost of {main_info['cost']}")

    # Join the sentence parts
    if len(sentence_parts) == 1:
        sentence = sentence_parts[0]
    elif len(sentence_parts) == 2:
        sentence = f"{sentence_parts[0]} {sentence_parts[1]}"
    else:
        sentence = f"{sentence_parts[0]}, {', '.join(sentence_parts[1:-1])}, and {sentence_parts[-1]}"

    # Ensure proper capitalization and punctuation
    sentence = sentence[0].upper() + sentence[1:]
    if not sentence.endswith('.'):
        sentence += '.'

    return sentence

# EVOLVE-BLOCK-END
